                    },
                    "content": [
                      {
                        "text": "[ ] What branch naming pattern will the Junior Developer agent use for its PRs? (This determines the ",
                        "type": "text"
                      },
                      {
                        "marks": [
                          {
                            "type": "code"
                          }
                        ],
                        "text": "branches:",
                        "type": "text"
                      },
                      {
                        "text": " filter in ",
                        "type": "text"
                      },
                      {
                        "marks": [
                          {
                            "type": "code"
                          }
                        ],
                        "text": "testing.yml",
                        "type": "text"
                      },
                      {
                        "text": " — to be decided in KAN-2 and referenced here.)",
                        "type": "text"
                      }
                    ],
                    "type": "paragraph"
                  }
                ],
                "type": "listItem"
              }
            ],
